var _ INfcFCardEmulation = (*nfcFCardEmulationStubWrapper)(nil)

// NewNfcFCardEmulationStub creates a server-side INfcFCardEmulation wrapping the given
// server implementation. The returned value satisfies INfcFCardEmulation
// and can be passed to proxy methods; its AsBinder() returns a
// *binder.StubBinder that is auto-registered with the binder
// driver on first use.
func NewNfcFCardEmulationStub(
	impl INfcFCardEmulationServer,
) INfcFCardEmulation {
	wrapper := &nfcFCardEmulationStubWrapper{impl: impl}
	stub := &NfcFCardEmulationStub{Impl: wrapper}
	wrapper.stubBinder = binder.NewStubBinder(stub)
	return wrapper
}
